   229	                        immediateOffset,
   230	                        unsignedVal);
   231	                }
   232	            }
   233	        }
   234	
   235	        return emitSimpleStore(type, buffer, baseOffset, immediateOffset, value);
   236	    }
   237	
   238	    Result emitSimpleStore(
   239	        IRType* type,
   240	        IRInst* buffer,
   241	        IRInst* baseOffset,
   242	        IRIntegerValue immediateOffset,
   243	        IRInst* value)
   244	    {
   245	        IRInst* offset = emitOffsetAddIfNeeded(baseOffset, immediateOffset);
   246	        if (m_options.translateToStructuredBufferOps)
   247	        {
   248	            if (auto structuredBuffer = getEquivalentStructuredBuffer(type, buffer))
   249	            {
   250	                // Similar to the load case, if we are replacing byte-address
   251	                // buffers with structured buffers, then once we find the
   252	                // "equivalent" buffer to use, we emit a structured-buffer store,
   253	                // with an index computed by dividing the offset by the stride.
   254	                //
   255	                auto indexType = offset->getDataType();
   256	
   257	                IRSizeAndAlignment typeLayout;
   258	                SLANG_RETURN_ON_FAIL(getNaturalSizeAndAlignment(m_target, type, &typeLayout));
   259	
   260	                auto typeStride = m_builder.getIntValue(indexType, typeLayout.getStride());
   261	
   262	                IRInst* divArgs[] = {offset, typeStride};
   263	                auto index = m_builder.emitIntrinsicInst(indexType, kIROp_Div, 2, divArgs);
   264	
   265	                IRInst* args[] = {structuredBuffer, index, value};
   266	                m_builder.emitIntrinsicInst(type, kIROp_RWStructuredBufferStore, 3, args);
   267	                return SLANG_OK;
   268	            }
   269	        }
   270	        if (m_options.lowerBasicTypeOps)
   271	        {
   272	            // Some platforms e.g. Metal does not allow storing basic types that are not 4-byte
   273	            // sized. We need to lower such stores.
   274	            IRSizeAndAlignment sizeAlignment;
   275	            SLANG_RETURN_ON_FAIL(getNaturalSizeAndAlignment(m_target, type, &sizeAlignment));
   276	            if (sizeAlignment.size == 8)
   277	            {
   278	                // We need to store the value as two 4-byte values.
   279	                // For pointer types, Metal doesn't allow as_type casts from pointers to integers,
   280	                // so we use proper cast operations instead of bit casts.
   281	                IRInst* loVal;
   282	                IRInst* hiVal;
   283	                IRInst* uint64Val;
   284	                if (type->getOp() == kIROp_PtrType || type->getOp() == kIROp_RawPointerType)
   285	                {
   286	                    // Use proper cast operation instead of bit cast for pointers
   287	                    uint64Val = m_builder.emitCastPtrToInt(value);
   288	                }
   289	                else
   290	                {
   291	                    // For non-pointer 64-bit types (including IntPtr/UIntPtr)
   292	                    uint64Val = m_builder.emitBitCast(m_builder.getUInt64Type(), value);
   293	                }
   294	                loVal = m_builder.emitCast(m_builder.getUIntType(), uint64Val);
   295	                hiVal = m_builder.emitCast(
   296	                    m_builder.getUIntType(),
   297	                    m_builder.emitShr(
   298	                        m_builder.getUInt64Type(),
   299	                        uint64Val,
   300	                        m_builder.getIntValue(m_builder.getUInt64Type(), 32)));
   301	                auto loOffset = offset;
   302	                auto hiOffset = emitOffsetAddIfNeeded(offset, 4);
   303	                IRInst* alignment = m_builder.getIntValue(m_builder.getUIntType(), 0);
   304	                m_builder.emitByteAddressBufferStore(buffer, loOffset, alignment, loVal);
   305	                m_builder.emitByteAddressBufferStore(buffer, hiOffset, alignment, hiVal);
   306	                return SLANG_OK;
   307	            }
   308	            else if (sizeAlignment.size < 4)
   309	            {
   310	                IRInst* loadArgs[] = {buffer, offset};
   311	                auto existingVal = m_builder.emitIntrinsicInst(
   312	                    m_builder.getUIntType(),
   313	                    kIROp_ByteAddressBufferLoad,
   314	                    2,
   315	                    loadArgs);
   316	                auto alignedOffset = m_builder.emitDiv(
   317	                    offset->getDataType(),
   318	                    offset,
   319	                    m_builder.getIntValue(offset->getDataType(), 4));
   320	                alignedOffset = m_builder.emitMul(
   321	                    offset->getDataType(),
   322	                    alignedOffset,
   323	                    m_builder.getIntValue(offset->getDataType(), 4));
   324	                auto shiftAmount = m_builder.emitSub(offset->getDataType(), offset, alignedOffset);
   325	                shiftAmount = m_builder.emitMul(
   326	                    offset->getDataType(),
   327	                    shiftAmount,
   328	                    m_builder.getIntValue(offset->getDataType(), 8));
   329	                auto uintVal = m_builder.emitCast(
   330	                    m_builder.getUIntType(),
   331	                    m_builder.emitBitCast(getSameSizeUIntType(value->getDataType()), value));
   332	                auto shiftedData = m_builder.emitShl(m_builder.getUIntType(), uintVal, shiftAmount);
   333	                IRInst* mask = nullptr;
   334	                switch (sizeAlignment.size)
   335	                {
   336	                case 1:
   337	                    mask = m_builder.getIntValue(m_builder.getUIntType(), 0xFF);
   338	                    break;
   339	                case 2:
   340	                    mask = m_builder.getIntValue(m_builder.getUIntType(), 0xFFFF);
   341	                    break;
   342	                default:
   343	                    SLANG_ASSERT(!"Unexpected size");
   344	                    return SLANG_FAIL;
   345	                }
   346	                mask = m_builder.emitShl(m_builder.getUIntType(), mask, shiftAmount);
   347	                mask = m_builder.emitBitNot(m_builder.getUIntType(), mask);
   348	                auto maskedData = m_builder.emitBitAnd(m_builder.getUIntType(), existingVal, mask);
   349	                auto newData =
   350	                    m_builder.emitBitOr(m_builder.getUIntType(), maskedData, shiftedData);
   351	                m_builder.emitByteAddressBufferStore(buffer, alignedOffset, newData);
   352	                return SLANG_OK;
   353	            }
   354	        }
   355	        {
   356	            m_builder.emitByteAddressBufferStore(buffer, offset, value);
   357	            return SLANG_OK;
   358	        }
   359	    }
   360	
   361	    Result emitLegalSequenceStore(
   362	        IRInst* buffer,
   363	        IRInst* baseOffset,
   364	        IRIntegerValue immediateOffset,
   365	        IRInst* value,
   366	        IRType* elementType,
   367	        IRIntegerValue elementCount,
   368	        IRInst* alignment)
   369	    {
   370	        // The store case for sequences is similar to the load case.
   371	        //
   372	        // We iterate over the elements and fetch then store each one.
   373	        //
   374	        IRSizeAndAlignment elementLayout;
   375	        SLANG_RETURN_ON_FAIL(getNaturalSizeAndAlignment(m_target, elementType, &elementLayout));
   376	        IRIntegerValue elementStride = elementLayout.getStride();
   377	
   378	        auto indexType = m_builder.getIntType();
   379	        for (IRIntegerValue ii = 0; ii < elementCount; ++ii)
   380	        {
   381	            auto elementIndex = m_builder.getIntValue(indexType, ii);
   382	            auto elementVal = m_builder.emitElementExtract(elementType, value, elementIndex);
   383	            SLANG_RETURN_ON_FAIL(emitLegalStore(
   384	                elementType,
   385	                buffer,
   386	                baseOffset,
   387	                immediateOffset + ii * elementStride,
   388	                alignment,
   389	                elementVal));
   390	        }
   391	
   392	        return SLANG_OK;
   393	    }
   394	};
   395	
   396	
   397	void legalizeByteAddressBufferOps(
   398	    IRModule* module,
   399	    Session* session,
   400	    TargetProgram* program,
   401	    DiagnosticSink* sink,
   402	    ByteAddressBufferLegalizationOptions const& options)
   403	{
   404	    ByteAddressBufferLegalizationContext context;
   405	    context.m_session = session;
   406	    context.m_target = program->getTargetReq();
   407	    context.m_options = options;
   408	    context.m_targetProgram = program;
   409	    context.m_sink = sink;
   410	    context.processModule(module);
   411	}
   412	
   413	
