   648	// CUDA layout rules extend C layout rules with CUDA-specific vector alignment.
   649	// CUDA vector types (float2, float3, float4, etc.) have special alignment requirements:
   650	// - vec2: 2 * element size (e.g., float2 is 8-byte aligned)
   651	// - vec3: element size (e.g., float3 is 4-byte aligned, NOT 12 or 16)
   652	// - vec4: 4 * element size (e.g., float4 is 16-byte aligned)
   653	// This matches CUDA C++ compiler behavior for native vector types like float4, int2, etc.
   654	struct CUDALayoutRules : CLayoutRules
   655	{
   656	    CUDALayoutRules() { ruleName = IRTypeLayoutRuleName::CUDA; }
   657	
   658	    virtual IRSizeAndAlignment getVectorSizeAndAlignment(
   659	        IRSizeAndAlignment element,
   660	        IRIntegerValue count)
   661	    {
   662	        IRIntegerValue size = element.size * count;
   663	        IRIntegerValue alignment;
   664	
   665	        if (count == 3)
   666	        {
   667	            // vec3 has same alignment as element (e.g., float3 is 4-byte aligned)
   668	            alignment = element.alignment;
   669	        }
   670	        else
   671	        {
   672	            // vec2, vec4, etc. have power-of-2 alignment
   673	            // float2 -> 8-byte, float4 -> 16-byte, double2 -> 16-byte
   674	            alignment = element.alignment * count;
   675	        }
   676	
   677	        // CUDA caps vector alignment at 16 bytes (per vector_types.h)
   678	        // This ensures double4 and longlong4 use 16-byte alignment, not 32-byte
   679	        if (alignment > 16)
   680	            alignment = 16;
   681	
   682	        return IRSizeAndAlignment(size, (int)alignment);
   683	    }
