    37	        }
    38	        break;
    39	    case kIROp_PtrType:
    40	    case kIROp_IntPtrType:
    41	    case kIROp_UIntPtrType:
    42	    case kIROp_RawPointerType:
    43	    case kIROp_NativePtrType:
    44	    case kIROp_ComPtrType:
    45	    case kIROp_PseudoPtrType:
    46	    case kIROp_RTTIPointerType:
    47	    case kIROp_OutParamType:
    48	    case kIROp_BorrowInOutParamType:
    49	    case kIROp_RefParamType:
    50	    case kIROp_BorrowInParamType:
    51	    case kIROp_NativeStringType:
    52	    case kIROp_FuncType:
    53	        // Pointer-like and fixed-size types don't embed their pointee/operand,
    54	        // so they break dependency cycles. Do not recurse into operand types.
    55	        break;
    56	    default:
    57	        {
    58	            for (UInt i = 0; i < type->getOperandCount(); i++)
    59	            {
    60	                if (auto operandType = as<IRType>(type->getOperand(i)))
    61	                    _findDependenciesOfTypeInSet(operandType, targetSet, result);
    62	            }
    63	        }
    64	        break;
    65	    }
    66	}
    67	
    68	List<IRInterfaceType*> findDependenciesOfTypeInSet(
    69	    IRType* type,
    70	    HashSet<IRInterfaceType*> targetSet)
    71	{
    72	    List<IRInterfaceType*> result;
    73	    _findDependenciesOfTypeInSet(type, targetSet, result);
    74	
    75	    return result;
    76	}
