    89	    for (auto dependency : getDependencies(interfaceType))
    90	    {
    91	        _sortTopologically(dependency, visited, sortedInterfaceTypes, getDependencies);
    92	    }
    93	
    94	    sortedInterfaceTypes.add(interfaceType);
    95	}
